module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
  .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
const text = (args.text != null && String(args.text).trim() !== '') ? String(args.text).trim() : 'CONFIDENTIAL';
const variant = (['double', 'solid', 'outline', 'plain'].indexOf(String(args.variant || 'double').toLowerCase()) >= 0)
  ? String(args.variant).toLowerCase() : 'double';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
return '<span class="mdp-mod-stamp mdp-stamp--' + variant + '" style="--stamp-color: ' + color + ';">'
  + esc(text) + '</span>';
